# Since the company name did not resolve to an ID even with a fuzzy match, we need to check if there are any similar names
query_company_id_similar = text("SELECT id, name FROM polluting_company WHERE name ILIKE '%Shougang Jingtang Steel%'")
company_id_result_similar = engine.connect().execute(query_company_id_similar).fetchall()

if company_id_result_similar:
    print('Found similar company names:')
    for row in company_id_result_similar:
        print(f'ID: {row[0]}, Name: {row[1]}')
else:
    print('No similar company names found.')
